		}
	}
	systemDensity := activeRoutes / float64(MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		saved[i].station = dispatch.Assigns[i].StationCurrent
		saved[i].cost = dispatch.Assigns[i].Cost
		oldCost := dispatch.Assigns[i].Cost
		if dispatch.Assigns[i].AddShip(shipID, ori, des) {
			dispatch.Assigns[i].GenRoute()
			newCost := dispatch.Assigns[i].Cost
			if newCost >= 0 && newCost >= oldCost-1e-9 {
				delta := newCost - oldCost
				routeUtilization := 0.0
				if oldCost > 0 {
					loadedDist := baseLoad * baseDist
					if loadedDist > 0 {
						routeUtilization = delta / loadedDist
					}
				}
				loadFactor := 1.0
				if baseLoad > 0 {
					loadFactor = 1.0 + gamma*baseLoad
				}
				proximityBonus := 0.0
