				oriY := float64(ori.Y)
				distToOrigin := math.Sqrt((curX-oriX)*(curX-oriX)+(curY-oriY)*(curY-oriY))
				if distToOrigin > 0 {
					proximityBonus = eta / distToOrigin
				}
				penalty := alpha * systemDensity * routeUtilization * loadFactor
				reward := beta * proximityBonus
				score := delta + penalty - reward
				candidates = append(candidates, cand{idx: i, score: score, deltaCost: delta, isNewSlot: false})
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].StationCurrent = saved[i].station
			dispatch.Assigns[i].Cost = saved[i].cost
		}
	}
