				}
				loadFactor := 1.0
				if baseLoad > 0 {
					loadFactor = 1.0 + gamma*baseLoad
				}
				penalty := alpha * newSystemDensity * routeUtilization * loadFactor
				score := delta + penalty
				candidates = append(candidates, cand{idx: j, score: score, deltaCost: delta, isNewSlot: true})
			}
			dispatch.Assigns[j].RemoveShip(shipID)
			dispatch.Assigns[j].StationCurrent = saved[j].station
			dispatch.Assigns[j].Cost = saved[j].cost
		}
	}
	bestIdx := -1
	bestScore := bigFloat
	for _, c := range candidates {
		if c.score < bestScore {
			bestScore = c.score
			bestIdx = c.idx
		}
	}
	if bestIdx >= 0 {
		dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
		dispatch.Assigns[bestIdx].GenRoute()
		if bestIdx >= dispatch.AssignsLen {
			dispatch.AssignsLen++
		}
	} else {
		inserted := false
		for retry := 0; retry < dispatch.AssignsLen; retry++ {
			if dispatch.Assigns[retry].AddShip(shipID, ori, des) {
				dispatch.Assigns[retry].GenRoute()
				inserted = true
				break
			}
		}
		if !inserted && dispatch.AssignsLen < MAXASSIGNS {
			k := dispatch.AssignsLen
			dispatch.Assigns[k].AddShip(shipID, ori, des)
			dispatch.Assigns[k].GenRoute()
			dispatch.AssignsLen++
			inserted = true
		}
		if !inserted {
			minCostIdx := 0
			minCost := dispatch.Assigns[0].Cost
			for r := 1; r < dispatch.AssignsLen; r++ {
				if dispatch.Assigns[r].Cost < minCost {
					minCost = dispatch.Assigns[r].Cost
					minCostIdx = r
				}
			}
			dispatch.Assigns[minCostIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[minCostIdx].GenRoute()
		}
	}
}
dispatch.RenewnTotalCost()
